'use client';
import React, { useEffect, useRef, useState } from "react";
import Link from "next/link";
import { motion, useReducedMotion, useInView } from "framer-motion";

export default function Hero() {
  const fullText = "Smarter money decisions, made simple";
  const [typed, setTyped] = useState("");
  const [headlineDone, setHeadlineDone] = useState(false);
  const [scrollY, setScrollY] = useState(0);
  const reduced = useReducedMotion();
  const containerRef = useRef<HTMLDivElement | null>(null);
  const inView = useInView(containerRef, { once: true, margin: "-10% 0px -10% 0px" });

  useEffect(() => {
    if (!inView) return;
    if (reduced) {
      setTyped(fullText);
      setHeadlineDone(true);
      return;
    }
    let i = 0;
    const id = setInterval(() => {
      i++;
      setTyped(fullText.slice(0, i));
      if (i >= fullText.length) {
        clearInterval(id);
        setTimeout(() => setHeadlineDone(true), 350);
      }
    }, 26);
    return () => clearInterval(id);
  }, [inView, reduced]);

  useEffect(() => {
    const onScroll = () => setScrollY(window.scrollY || 0);
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const letterSpacing = reduced ? "0px" : `${Math.max(0, 0.06 * (fullText.length - typed.length))}em`;
  const scrollOpacity = Math.max(0, 1 - scrollY / 140);

  return (
    <motion.section
      ref={containerRef}
      className="relative overflow-hidden pt-24 md:pt-28 min-h-[640px] flex items-center"
      style={{ height: "100svh" }}
      initial={{ opacity: 0, y: 10 }}
      animate={inView ? { opacity: 1, y: 0 } : undefined}
      transition={{ duration: 0.6, ease: "easeOut" }}
    >
      <div className="absolute inset-0 -z-10 mesh-bg will-change-transform" />
      <div className="absolute inset-0 -z-10 particles">
        {Array.from({ length: 12 }).map((_, i) => (
          <span key={i} className="particle" />
        ))}
      </div>
      <span
        style={{ transform: `translateY(${scrollY * 0.06}px)` }}
        className="pointer-events-none absolute left-[15%] top-10 h-64 w-64 rounded-full bg-[var(--color-primary-100)] blur-3xl opacity-60"
      />
      <span
        style={{ transform: `translateY(${scrollY * 0.04}px)` }}
        className="pointer-events-none absolute right-[12%] top-24 h-72 w-72 rounded-full bg-[var(--color-accent-50)] blur-3xl opacity-50"
      />

      <div className="mx-auto max-w-6xl px-6">
        <motion.h1
          className="text-4xl md:text-5xl font-semibold tracking-tight text-gray-900"
          style={{ letterSpacing }}
          initial={{ opacity: 0 }}
          animate={inView ? { opacity: 1 } : undefined}
          transition={{ duration: 0.4 }}
        >
          {typed}
          {!reduced && <span className="caret">|</span>}
        </motion.h1>
        <motion.p
          className="mt-5 md:mt-6 max-w-[65ch] text-base md:text-lg text-gray-700"
          initial={{ opacity: 0, y: 12 }}
          animate={headlineDone ? { opacity: 1, y: 0 } : undefined}
          transition={{ duration: 0.5, ease: "easeOut" }}
        >
          Pennywise turns budgeting and financial literacy into clear, personalized guidance you
          can act on today—backed by sources and tailored to your situation.
        </motion.p>
        <div className="mt-7 md:mt-8 flex items-center gap-3">
          <motion.div
            initial={{ opacity: 0, scale: 0.92 }}
            animate={headlineDone && inView ? { opacity: 1, scale: 1 } : undefined}
            transition={{ type: "spring", stiffness: 140, damping: 15, delay: 0.15 }}
          >
            <Link
              href="/signup"
              onClick={(e) => {
                const target = e.currentTarget;
                const rect = target.getBoundingClientRect();
                const size = Math.max(rect.width, rect.height);
                const ripple = document.createElement("span");
                ripple.className = "ripple";
                ripple.style.width = `${size}px`;
                ripple.style.height = `${size}px`;
                ripple.style.left = `${e.clientX - rect.left - size / 2}px`;
                ripple.style.top = `${e.clientY - rect.top - size / 2}px`;
                target.appendChild(ripple);
                setTimeout(() => ripple.remove(), 650);
              }}
              className="relative overflow-hidden rounded-md bg-gray-900 px-4 py-2 text-sm text-white transition-all hover:opacity-90 hover:scale-[1.05] hover:shadow-md animate-[glowPulse_3s_ease-in-out_infinite] will-change-transform"
            >
              Get Started Free
            </Link>
          </motion.div>
          <motion.div
            initial={{ opacity: 0, scale: 0.92 }}
            animate={headlineDone && inView ? { opacity: 1, scale: 1 } : undefined}
            transition={{ type: "spring", stiffness: 140, damping: 15, delay: 0.25 }}
          >
            <Link
              href="/login"
              className="rounded-md border px-4 py-2 text-sm transition-all hover:bg-black/5 hover:scale-[1.05] hover:shadow-md will-change-transform"
            >
              Sign In
            </Link>
          </motion.div>
        </div>
        <p className="mt-5 md:mt-6 text-xs text-gray-600">Private by design • Source-backed guidance</p>
      </div>

      <motion.div
        className="absolute bottom-6 left-1/2 -translate-x-1/2"
        style={{ opacity: scrollOpacity }}
        initial={{ opacity: 0 }}
        animate={inView ? { opacity: 1 } : undefined}
        transition={{ duration: 0.6 }}
      >
        <Link href="#below-hero" className="flex items-center gap-3 text-gray-500">
          <div className="flex h-9 w-[22px] items-start justify-center rounded-full border">
            <span className="scroll-indicator-dot" />
          </div>
          <span className="text-xs">Scroll</span>
        </Link>
      </motion.div>
    </motion.section>
  );
}
